SET ANSI_NULLS ON;
GO
SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE dbo.usp_get_competing_country_result_listings(
    @competing_country_code NCHAR(2)
)
AS

/*
-- =============================================
-- Function:    dbo.usp_get_competing_country_result_listings
-- Author:      Matt Tantony
-- Create date: 2025-11-16
--
--
-- Description:
-- ============
--  Returns a list of all the results for a specified competing country.
--
--  Listings are generated by:
--      - Filtering voting data from query parameters.
--      - Compiling result listings.
--      - Sorting listings
--          - by contest year (descending),
--          - then by contest stage (SemiFinal1 < SemiFinal2 < GrandFinal).
--
--
-- Required input parameters:
-- ==========================
--  @competing_country_code NCHAR(2)
--      - Filters voting data by competing country code.
--
--
-- Returns:
-- ========
-- A list of 0, 1, or multiple listings rows with the following columns:
--  - contest_year INT
--      - The contest year of the broadcast.
--  - contest_stage NVARCHAR(10)
--      - The broadcast's stage in the contest.
--      - Valid 'ContestStage' enum values: {'SemiFinal1', 'SemiFinal2', 'GrandFinal'}.
--  - running_order_spot INT
--      - The competitor's running order spot in the broadcast.
--  - act_name NVARCHAR(200)
--      - The competitor's act name.
--  - song_title NVARCHAR(200)
--      - The competitor's song title.
--  - jury_points INT
--      - The total jury points the competitor received, or NULL in a televote-only broadcast.
--      - Allows NULL.
--  - jury_rank INT
--      - The competitor's rank based on total jury points, or NULL in a televote-only broadcast.
--      - Allows NULL.
--  - televote_points INT
--      - The total televote points the competitor received.
--  - televote_rank INT
--      - The competitor's rank based on total televote points.
--  - overall_points INT
--      - The total overall points the competitor received.
--  - finishing_position INT
--      - The competitor's finishing position in the broadcast.
--  - competitors INT
--      - The number of competitors in the broadcast.
-- =============================================
*/


BEGIN

    SET NOCOUNT ON;

-- Filter voting data

    WITH filtered_broadcast_competitor AS (SELECT b.broadcast_id,
                                                  bc.competing_country_id,
                                                  k.contest_year,
                                                  b.contest_stage,
                                                  dbo.udf_get_contest_stage_sort_order_value(b.contest_stage) AS contest_stage_sort_order,
                                                  bc.running_order_spot,
                                                  cp.act_name,
                                                  cp.song_title,
                                                  bc.finishing_position

                                           FROM dbo.contest k
                                                    JOIN dbo.broadcast b ON b.parent_contest_id = k.contest_id
                                                    JOIN dbo.contest_participant cp ON cp.contest_id = k.contest_id
                                                    JOIN dbo.country c ON c.country_id = cp.participating_country_id
                                                    JOIN dbo.broadcast_competitor bc
                                                         ON bc.broadcast_id = b.broadcast_id AND
                                                            bc.competing_country_id = c.country_id
                                           WHERE k.queryable = 1
                                             AND c.country_code = @competing_country_code),

         points_subtotal AS (SELECT bcta.broadcast_id,
                                    bcta.competing_country_id,
                                    SUM(bcja.points_value) AS jury_points,
                                    SUM(bcta.points_value) AS televote_points
                             FROM dbo.broadcast_competitor_televote_award bcta
                                      JOIN filtered_broadcast_competitor fbc ON fbc.broadcast_id = bcta.broadcast_id
                                      LEFT JOIN dbo.broadcast_competitor_jury_award bcja
                                                ON bcja.broadcast_id = bcta.broadcast_id
                                                    AND bcja.competing_country_id = bcta.competing_country_id
                                                    AND bcja.voting_country_id = bcta.voting_country_id
                             GROUP BY bcta.broadcast_id, bcta.competing_country_id),

-- Compile listings, sort, and return listings rows

         ranked_points AS (SELECT ps.broadcast_id,
                                  ps.competing_country_id,
                                  ps.jury_points,
                                  IIF(ps.jury_points IS NULL, NULL,
                                      RANK() OVER (PARTITION BY ps.broadcast_id ORDER BY ps.jury_points DESC)) AS jury_rank,
                                  ps.televote_points,
                                  RANK() OVER (PARTITION BY ps.broadcast_id ORDER BY ps.televote_points DESC)  AS televote_rank,
                                  COALESCE(ps.jury_points, 0) + ps.televote_points                             AS overall_points,
                                  COUNT(*) OVER (PARTITION BY ps.broadcast_id)                                 AS competitors
                           FROM points_subtotal ps)

    SELECT fbc.contest_year,
           fbc.contest_stage,
           fbc.running_order_spot,
           fbc.act_name,
           fbc.song_title,
           rp.jury_points,
           rp.jury_rank,
           rp.televote_points,
           rp.televote_rank,
           rp.overall_points,
           fbc.finishing_position,
           rp.competitors
    FROM ranked_points rp
             JOIN filtered_broadcast_competitor fbc ON fbc.broadcast_id = rp.broadcast_id
        AND fbc.competing_country_id = rp.competing_country_id
    ORDER BY fbc.contest_year, fbc.contest_stage_sort_order;


END

GO
